import { Navigate, Outlet, useLocation, useParams } from "@remix-run/react";
import { useEffect } from "react";
import i18n, { defaultLng } from "~/i18n";
import { normalizeLanguageCode } from "~/i18n/languages";

export default function LangLayout() {
  const { lang } = useParams<{ lang: string }>();
  const location = useLocation();
  const normalized = normalizeLanguageCode(lang);

  useEffect(() => {
    const targetLng = normalized || defaultLng;
    if (i18n.language !== targetLng) {
      i18n.changeLanguage(targetLng);
    }
  }, [normalized]);

  if (!normalized) {
    const currentLng = i18n.language || defaultLng;
    return (
      <Navigate
        to={`/${currentLng}${location.pathname}${location.search}`}
        replace
      />
    );
  }

  return <Outlet />;
}
