import i18next from "i18next";
import { initReactI18next } from "react-i18next";
import LanguageDetector from "i18next-browser-languagedetector";
import resourcesToBackend from "i18next-resources-to-backend";
import {
  defaultLng,
  getLocaleResourceCode,
  normalizeLanguageCode,
  supportedLngs,
} from "./languages";

export const defaultNS = "translation";
export const i18nLocalStorageKey = "orderly_one_i18nLng";
export { defaultLng, supportedLngs } from "./languages";

import enTranslations from "./translations/en";

function getUrlLng(): string | null {
  if (typeof window === "undefined") return null;
  const firstSegment = window.location.pathname.split("/").filter(Boolean)[0];
  const pathLng = normalizeLanguageCode(firstSegment);
  if (pathLng) return pathLng;
  const params = new URLSearchParams(window.location.search);
  return normalizeLanguageCode(params.get("lng"));
}

function setUrlLng(lng: string) {
  if (typeof window === "undefined") return;
  const nextLng = normalizeLanguageCode(lng) || defaultLng;
  const url = new URL(window.location.href);
  const segments = url.pathname.split("/").filter(Boolean);
  const hasLocalePrefix =
    segments.length > 0 && Boolean(normalizeLanguageCode(segments[0]));

  if (hasLocalePrefix) {
    segments.shift();
  }

  url.pathname = `/${[nextLng, ...segments].join("/")}`;
  url.searchParams.delete("lng");
  window.history.replaceState({}, "", url.toString());
}

const urlLng = getUrlLng();

const i18n = i18next
  .use(initReactI18next)
  .use(
    resourcesToBackend((lng: string, _ns: string) => {
      const resourceLng = getLocaleResourceCode(lng);
      if (resourceLng === "en") {
        return Promise.resolve(enTranslations);
      }
      return import(`./locales/${resourceLng}.json`).then(module => {
        const data = module.default || module;
        return data;
      });
    })
  )
  .use(LanguageDetector);

i18n.init({
  lng: urlLng || undefined,
  fallbackLng: defaultLng,
  supportedLngs,
  nonExplicitSupportedLngs: true,
  defaultNS,
  ns: [defaultNS],
  keySeparator: false,
  nsSeparator: false,
  interpolation: {
    escapeValue: false,
  },
  react: {
    useSuspense: false,
  },
  detection: {
    order: urlLng
      ? ["querystring", "localStorage", "navigator"]
      : ["localStorage", "navigator"],
    lookupQuerystring: "lng",
    lookupLocalStorage: i18nLocalStorageKey,
    caches: ["localStorage"],
  },
});

if (urlLng) {
  setUrlLng(urlLng);
}

i18n.on("languageChanged", (lng: string) => {
  setUrlLng(lng);
});

export default i18n;
